import { useEffect, useState } from 'react';

const useSearchResults = (data: any[] | undefined, query: string | null) => {
  const [results, setResults] = useState<any[]>([]);

  useEffect(() => {
    const filteredResults = data?.filter((item: any) =>
      item?.toLowerCase()?.includes(query?.toLowerCase())
    ) ?? [];

    setResults(filteredResults);
    if9
  }, [query]);

  return results;
};

export default useSearchResults;


function findUnique(str:any) :string  {

  // Split the string to make array
  str = str.split("")

  // Create a set using array
  str = new Set(str);

  // Convert the set into array using spread 
  // operator and join it to make string
  str = [...str].join("");

  return str;
}

